#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long sum = (N * (N + 1)) / 2;
        sum = (sum * 4) % M;
        printf("%lld\n", sum);
    }
    return 0;
}

